// Filtrar y seleccionar la mejor keyword no usada
// Criterios: volumen > 500, dificultad < 40, no usada antes

const response = $input.item.json;
const tasks = response.tasks || [];
const result = tasks[0]?.result || [];

// Filtrar keywords con volumen > 500
const keywordsFiltradas = result
  .filter(kw => {
    const volume = kw.search_volume || 0;
    const difficulty = kw.keyword_difficulty || 100;
    return volume >= 500 && difficulty < 40;
  })
  .map(kw => ({
    keyword: kw.keyword,
    volume: kw.search_volume,
    difficulty: kw.keyword_difficulty || 0,
    cpc: kw.cpc || 0,
    competition: kw.competition || 0
  }));

// Ordenar por volumen descendente
keywordsFiltradas.sort((a, b) => b.volume - a.volume);

// Leer keywords ya usadas (desde Google Sheets en la implementacion real)
// Por ahora simulamos con array vacio - reemplazar con lectura real
const keywordsUsadas = [];

// Seleccionar la primera no usada
const keywordSeleccionada = keywordsFiltradas.find(
  kw => !keywordsUsadas.includes(kw.keyword)
);

if (!keywordSeleccionada) {
  throw new Error('No hay keywords disponibles que cumplan los criterios');
}

// Generar slug a partir de la keyword
const slug = keywordSeleccionada.keyword
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '');

const fecha = new Date().toISOString().split('T')[0];
const nombreArchivo = `${slug}-${fecha}.md`;

return {
  json: {
    keyword_seleccionada: keywordSeleccionada.keyword,
    volumen: keywordSeleccionada.volume,
    dificultad: keywordSeleccionada.difficulty,
    cpc: keywordSeleccionada.cpc,
    slug: slug,
    nombre_archivo: nombreArchivo,
    fecha: fecha,
    cliente: 'don-jacinto-nahual',
    sitio_web: 'donjacintonahual.com',
    url_articulo: `https://donjacintonahual.com/blog/${slug}/`
  }
};

// Combinar el articulo generado con metadata del workflow
const articulo = $input.item.json.content?.[0]?.text || $input.item.json.message?.content?.[0]?.text || $input.item.json.text || (typeof $input.item.json.content === 'string' ? $input.item.json.content : '') || '';

// Recuperar datos del nodo anterior
const metadata = $('Seleccionar Mejor Keyword').item.json;

// Validar que el articulo tiene frontmatter
if (!articulo.startsWith('---')) {
  throw new Error('El articulo generado no tiene frontmatter valido');
}

// Validar longitud minima
if (articulo.length < 5000) {
  throw new Error(`Articulo muy corto: ${articulo.length} caracteres (minimo 5000)`);
}

return {
  json: {
    ...metadata,
    contenido_articulo: articulo,
    contenido_base64: Buffer.from(articulo).toString('base64'),
    longitud_caracteres: articulo.length,
    commit_message: `blog: articulo SEO - ${metadata.keyword_seleccionada}`,
    ruta_archivo: `src/content/blog/${metadata.nombre_archivo}`
  }
};
